UPDATE CMN_NOTICE_MST
SET 
	TITLE				=  #{TITLE}
	,CONTENTS		= #{CONTENTS}
	,DELETE_YN		= NVL( #{DELETE_YN}, 'N')
	,POST_STRT_DT  = #{POST_STRT_DT}
	,POST_END_DT   = #{POST_END_DT}
	,RVISN_ID			= #{SESSION_USER_ID}
	,RVISN_DTTM	= SYSDATE
	,ORGN			= NVL( #{ORGN}, 0)
	,ORGN10			= NVL( #{ORGN10}, 0)
	,ORGN20			= NVL( #{ORGN20}, 0)
	,ORGN40			= NVL( #{ORGN40}, 0)
	,RVISN_ORGN_NM = ( SELECT A.ORGN_NM 
								FROM ORG_ORGN_INFO_MST A ,CMN_USR_MST B WHERE 1=1
								   AND A.ORGN_ID = B.ORGN_ID
								   AND B.USR_ID = #{SESSION_USER_ID}
								)
	,RVISN_USR_NM = (SELECT USR_NM FROM CMN_USR_MST WHERE USR_ID = #{SESSION_USER_ID})
WHERE NOTICE_ID = #{NOTICE_ID}

