/* boardMapper.updateBoardMgmt */
UPDATE  CMN_BOARD
SET     TITLE = #{title, jdbcType=VARCHAR}
        , CNTT = #{cntt, jdbcType=VARCHAR}
        , POST_STRT_DT = #{postStrtDt, jdbcType=VARCHAR}
        , POST_END_DT = #{postEndDt, jdbcType=VARCHAR}
        , ORGN_TP_CD1 = #{orgnTpCd1, jdbcType=VARCHAR}
        , ORGN_TP_CD2 = #{orgnTpCd2, jdbcType=VARCHAR}
        , ORGN_TP_CD3 = #{orgnTpCd3, jdbcType=VARCHAR}
        , ORGN_TP_CD4 = #{orgnTpCd4, jdbcType=VARCHAR}
        , ORGN_TP_CD5 = #{orgnTpCd5, jdbcType=VARCHAR}
        , RVISN_ID = #{sessionUserId, jdbcType=VARCHAR}
        , RVISN_DTTM = SYSDATE
WHERE   BOARD_CD = #{boardCd, jdbcType=VARCHAR}
AND     SRL_NUM = #{srlNum, jdbcType=INTEGER}

